import { create } from 'zustand';
import { persist } from 'zustand/middleware';

interface LikeStore { items: string[]; toggle: (id: string) => void; }

export const useLikeStore = create<LikeStore>()(persist(
  (set, get) => ({
    items: [],
    toggle: (id) => set({ items: get().items.includes(id) ? get().items.filter(i => i !== id) : [...get().items, id] }),
  }),
  { name: 'kitpick-likes' }
));
