import { create } from 'zustand';
import { persist } from 'zustand/middleware';

interface WishlistStore { items: string[]; toggle: (id: string) => void; }

export const useWishlistStore = create<WishlistStore>()(persist(
  (set, get) => ({
    items: [],
    toggle: (id) => set({ items: get().items.includes(id) ? get().items.filter(i => i !== id) : [...get().items, id] }),
  }),
  { name: 'kitpick-wishlist' }
));
