'use client';
import { useWishlistStore } from '@/store/wishlistStore';
import { DecisionCard } from '@/components/product/DecisionCard';
import { mockProducts } from '@/data/mockData';
import { Bookmark } from 'lucide-react';

export default function WishlistPage() {
  const { items } = useWishlistStore();
  const products = mockProducts.filter(p => items.includes(p.id));

  return (
    <div className="p-4 sm:p-6 lg:p-10">
      <div className="flex items-center gap-3 mb-8">
        <Bookmark className="w-6 h-6 text-brand-500" />
        <h1 className="text-2xl font-bold text-white">관심 목록</h1>
        <span className="text-sm text-zinc-500 ml-1">({products.length})</span>
      </div>
      {products.length > 0 ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {products.map(p => <DecisionCard key={p.id} product={p} />)}
        </div>
      ) : (
        <div className="text-center py-20">
          <Bookmark className="w-10 h-10 text-zinc-700 mx-auto mb-4" />
          <p className="text-zinc-500 text-sm">아직 관심 목록이 비어있어요</p>
          <p className="text-zinc-600 text-xs mt-1">피드에서 북마크 버튼을 눌러 추가해보세요</p>
        </div>
      )}
    </div>
  );
}
