'use client';
import Link from 'next/link';
import { Heart, Bookmark, ArrowUpRight, ArrowDownRight } from 'lucide-react';
import { DecisionBadge } from '@/components/ui/DecisionBadge';
import { useWishlistStore } from '@/store/wishlistStore';
import { useLikeStore } from '@/store/likeStore';
import type { Product } from '@/data/mockData';

export function DecisionCard({ product }: { product: Product }) {
  const { items: wishItems, toggle: toggleWish } = useWishlistStore();
  const { items: likeItems, toggle: toggleLike } = useLikeStore();
  const isWished = wishItems.includes(product.id);
  const isLiked  = likeItems.includes(product.id);
  const priceDiff = product.price - product.prevPrice;
  const pctChange = Math.round((priceDiff / product.prevPrice) * 100);

  return (
    <div className="bg-surface border border-surface-border rounded-xl overflow-hidden hover:border-surface-border-light transition-colors group">
      <div className={`h-1 ${product.decision === 'buy' ? 'bg-decision-buy' : product.decision === 'wait' ? 'bg-decision-wait' : product.decision === 'watch' ? 'bg-decision-watch' : 'bg-decision-trending'}`} />
      <div className="p-4">
        <div className="flex items-start justify-between mb-3">
          <div className="flex-1 min-w-0 pr-2">
            <p className="text-[11px] text-zinc-500 mb-0.5">{product.series}</p>
            <Link href={`/product/${product.id}`}>
              <h3 className="text-sm font-semibold text-white leading-snug group-hover:text-brand-400 transition-colors line-clamp-2">{product.name}</h3>
            </Link>
            <p className="text-[11px] text-zinc-600 mt-0.5">{product.grade}</p>
          </div>
          <DecisionBadge decision={product.decision} />
        </div>
        <p className="text-xs text-zinc-500 leading-relaxed mb-4 line-clamp-2">{product.reasoning}</p>
        <div className="flex items-center justify-between">
          <div>
            <p className="text-base font-bold text-white">{product.price.toLocaleString()}원</p>
            <div className={`flex items-center gap-0.5 text-[11px] font-medium ${priceDiff < 0 ? 'text-green-400' : priceDiff > 0 ? 'text-red-400' : 'text-zinc-500'}`}>
              {priceDiff < 0 ? <ArrowDownRight size={12} /> : priceDiff > 0 ? <ArrowUpRight size={12} /> : null}
              {priceDiff !== 0 ? `${Math.abs(pctChange)}%` : '변동없음'}
            </div>
          </div>
          <div className="flex items-center gap-1">
            <button onClick={e => { e.preventDefault(); toggleLike(product.id); }}
              className={`p-1.5 rounded-lg transition-colors ${isLiked ? 'text-red-400 bg-red-500/10' : 'text-zinc-600 hover:text-zinc-400 hover:bg-surface-raised'}`}>
              <Heart size={15} className={isLiked ? 'fill-current' : ''} />
            </button>
            <button onClick={e => { e.preventDefault(); toggleWish(product.id); }}
              className={`p-1.5 rounded-lg transition-colors ${isWished ? 'text-brand-500 bg-brand-500/10' : 'text-zinc-600 hover:text-zinc-400 hover:bg-surface-raised'}`}>
              <Bookmark size={15} className={isWished ? 'fill-current' : ''} />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
