type Decision = 'buy' | 'wait' | 'watch' | 'trending';
const CONFIG: Record<Decision, { label: string; color: string; bg: string; border: string }> = {
  buy:      { label: '구매 추천',  color: 'text-green-400', bg: 'bg-green-500/10', border: 'border-green-500/30' },
  wait:     { label: '기다리세요', color: 'text-amber-400', bg: 'bg-amber-500/10', border: 'border-amber-500/30' },
  watch:    { label: '지켜보세요', color: 'text-blue-400',  bg: 'bg-blue-500/10',  border: 'border-blue-500/30'  },
  trending: { label: '트렌딩',    color: 'text-brand-500', bg: 'bg-brand-500/10', border: 'border-brand-500/30' },
};
export function DecisionBadge({ decision, size = 'sm' }: { decision: Decision; size?: 'sm' | 'lg' }) {
  const cfg = CONFIG[decision];
  return (
    <span className={`inline-flex items-center font-semibold rounded-full border ${cfg.color} ${cfg.bg} ${cfg.border} ${size === 'lg' ? 'text-sm px-4 py-1.5' : 'text-[11px] px-2.5 py-0.5'}`}>
      {cfg.label}
    </span>
  );
}
